const TRUE = new Set(['true', 'yes', 'on', '1']);
const FALSE = new Set(['false', 'no', 'off', '0']);

function active(value) {
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number' && (value === 0 || value === 1)) return Boolean(value);
  if (typeof value === 'string') {
    const lowered = value.trim().toLowerCase();
    if (TRUE.has(lowered)) return true;
    if (FALSE.has(lowered)) return false;
  }
  throw new Error('invalid active');
}

export function normalizeRecord(record) {
  const locale = String(record.locale ?? '').trim() || 'en-US';
  const tags = [...new Set((record.tags ?? []).map((tag) => String(tag).trim().toLowerCase()).filter(Boolean))].sort();
  const score = Math.max(0, Math.min(100, Math.trunc(Number(record.score ?? 0))));
  return {id: String(record.id).trim().toLowerCase(), email: String(record.email).trim().toLowerCase(), active: active(record.active), tags, score, locale};
}

