def migrate(document):
    output = []
    suspended_count = 0
    for workspace in sorted(document['workspaces'], key=lambda row: row['id']):
        grouped = {}
        for member in workspace['members']:
            user = member['user'].strip().lower()
            current = grouped.get(user)
            if current is None or member.get('suspended', False) or (not current.get('suspended', False) and RANK[member['permission']] > RANK[current['permission']]):
                grouped[user] = member
        members = []
        for user, member in sorted(grouped.items()):
            if member.get('suspended', False):
                role, capabilities = 'suspended', []
                suspended_count += 1
            else:
                role, capabilities = MAPPING[member['permission']]
            members.append({'user': user, 'role': role, 'capabilities': capabilities})
        output.append({'id': workspace['id'], 'region': workspace['region'], 'members': members})
