def project(events):
    unique = {}
    for event in events:
        event_id = event['event_id']
        if event_id in unique and unique[event_id] != event:
            raise ValueError('conflicting event id')
        unique[event_id] = event
    grouped = {}
    for event in unique.values():
        grouped.setdefault(event['account'], []).append(event)
    accounts = []
    for account, assigned in sorted(grouped.items()):
        assigned = sorted(assigned, key=lambda row: row['seq'])
        if [row['seq'] for row in assigned] != list(range(1, len(assigned) + 1)):
            raise ValueError('non-contiguous account sequence')
        active = set()
        for event in assigned:
            if event['op'] == 'grant':
                active.add(event['entitlement'])
            elif event['op'] == 'revoke':
                active.discard(event['entitlement'])
            else:
                raise ValueError('invalid op')
        accounts.append({'account': account, 'last_seq': assigned[-1]['seq'], 'active': sorted(active)})
    return {'accounts': accounts, 'events_applied': len(unique)}
